"""
MKT Christ Commentary — Isaiah chapter 36
Run: python3 scripts/zc-christ-isaiah-36.py

Isaiah 36 is the historical narrative of Sennacherib's siege — the Rabshakeh's taunt
against Jerusalem and YHWH (paralleled in 2 Kings 18:13-36; 2 Chr 32:1-19).

The chapter is rich in passion-narrative typology:
- The Rabshakeh's "He trusts in YHWH, let YHWH deliver him" (vv.14-15) is the
  direct source of the Calvary mockers in Matt 27:43
- The people's commanded silence (v.21) → Isa 53:7; Jesus before accusers (Matt 26:63)
- Eliakim "who has the key of David" (22:22) → Rev 3:7 (Christ as key-holder)
- The false peace offer (v.16) → John 14:27 (not as the world gives)
- The idol-polemic challenge (vv.18-20) → Acts 4:12 (no other name for salvation)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ISAIAH = {
  "36": {
    "1": '<p>The historical crisis of Sennacherib\'s invasion sets the stage for one of the OT\'s most dramatic divine deliverances. The pattern — enemy powers apparently prevailing, then sudden divine intervention — is the template the NT applies to the passion and resurrection. Acts 2:23-24: "this Jesus, delivered up according to the definite plan and foreknowledge of God, you crucified and killed by the hands of lawless men. God raised him up, loosing the pangs of death, because it was not possible for him to be held by it." The Assyrian army surrounding Jerusalem and the Roman soldiers surrounding Calvary are parallel images of power arrayed against the community of faith — both resolved by unexpected divine action.</p>',
    "2": '<p>"And the king of Assyria sent the Rabshakeh with a great army from Lachish to King Hezekiah at Jerusalem." The Rabshakeh (field commander, spokesman of the conquering king) is a type of the Accuser who comes with an army of arguments against faith. The commission from the conquering king to overwhelm and demoralize the faithful is the pattern of spiritual warfare: 1 Pet 5:8, "the devil prowls around like a roaring lion, seeking someone to devour." John 12:31: "Now will the ruler of this world be cast out" — the Rabshakeh\'s boasting mission ends in his master\'s defeat; so does the devil\'s.</p>',
    "3": '<p>Eliakim son of Hilkiah — "who was over the household" — goes out with Shebna and Joah to meet the Rabshakeh. The connection to Isaiah 22:22 is critical: Eliakim is the one to whom YHWH gives "the key of the house of David; he shall open, and none shall shut; and he shall shut, and none shall open." Revelation 3:7 applies this language directly to Christ: "the words of the holy one, the true one, who has the key of David, who opens and no one will shut, who shuts and no one opens." Eliakim ("God raises up") is the type; Christ is the antitype — the one to whom authority over the household of David ultimately belongs.</p>',
    "4": '<p>"The Rabshakeh said to them, \'Say to Hezekiah, Thus says the great king, the king of Assyria: What is this confidence that you have?\'" The challenge to faith — "what is this confidence?" — is the fundamental challenge that the "ruler of this world" poses against every believer. 1 Cor 1:18: "the word of the cross is folly to those who are perishing, but to us who are being saved it is the power of God." The Rabshakeh\'s mockery of confidence in YHWH against visible military force is the original form of the world\'s scorn for faith in the crucified Christ.</p>',
    "5": '<p>"Do you think that mere words are strategy and power for war? In whom do you now trust, that you have rebelled against me?" The question "in whom do you trust?" is the fundamental Christological question. Heb 2:13: "I will put my trust in him" (Christ speaking, quoting Isa 8:17). Ps 22:8 (which the Calvary mockers quote): "he trusts in YHWH; let him deliver him." The Rabshakeh\'s contempt for "mere words" as military strategy is the contempt for the word of the cross — which is, in fact, "the power of God and the wisdom of God" (1 Cor 1:24).</p>',
    "6": '<p>"Behold, you are trusting in Egypt, that broken reed of a staff, which will pierce the hand of any man who leans on it. Such is Pharaoh king of Egypt to all who trust in him." The broken reed — the false ally that wounds rather than supports — is the NT\'s image of all human securities that fail under pressure. Jas 4:4: "do you not know that friendship with the world is enmity with God?" The misplaced trust in Egypt/human alliance is the recurring OT failure; the NT points to Christ as the only unbreakable support. 2 Cor 1:9-10: "we had the sentence of death... so that we would not trust in ourselves but in God who raises the dead."</p>',
    "7": '<p>"But if you say to me, \'We trust in YHWH our God,\' is it not he whose high places and altars Hezekiah has removed, saying to Judah and to Jerusalem, \'You shall worship before this altar\'?" The Rabshakeh\'s cynical misreading of Hezekiah\'s reform — treating the removal of high places as an offense against YHWH — is a type of the accusation against Jesus. The charge of blasphemy brought by the high priest (Matt 26:65) is the same structural error: what is most obedient to YHWH is presented as the greatest affront. The temple authorities see Jesus\'s authority to forgive sins as blasphemy; the Rabshakeh sees Hezekiah\'s obedience as provocation.</p>',
    "8": '<p>"Come now, make a wager with my master the king of Assyria: I will give you two thousand horses, if you are able to set riders on them." The offer of Assyrian horses to replace Judah\'s lack — conditional on Judah\'s acknowledgment of Assyrian superiority. The NT counterpart is Matt 4:8-9: the devil\'s offer of "all the kingdoms of the world and their glory" to Jesus, if only Jesus will worship him. Both offers come with a condition of submission; both are refused by the faithful. Jesus\'s refusal ("you shall worship the Lord your God and him only shall you serve") is the model for the refusal of the Rabshakeh\'s conditional offer.</p>',
    "9": '<p>"How then can you repulse a single captain among the least of my master\'s servants, when you trust in Egypt for chariots and for horsemen?" The Rabshakeh\'s argument from military incompetence to theological futility. The NT turns this logic on its head: God chose what is foolish and weak in the world to shame the wise and strong (1 Cor 1:27-28). The smallest forces of faith — the twelve apostles, the handful of believers at Pentecost — "repulsed" the Roman Empire and transformed the Mediterranean world. The assessment of military incompetence is the world\'s assessment; the resurrection\'s power operates by entirely different logic.</p>',
    "10": '<p>"Moreover, is it without YHWH that I have come up against this land to destroy it? YHWH said to me, \'Go up against this land, and destroy it.\'" The Rabshakeh claims divine authorization for his opposition — a claim the narrative ultimately shows to be both partially true (Assyria is YHWH\'s instrument of discipline, ch. 10) and finally refuted (the angel strikes the Assyrian army, ch. 37). The same ambiguity surrounds the crucifixion: it is "according to the definite plan and foreknowledge of God" (Acts 2:23) and yet the work of "lawless men" — divinely authorized and humanly guilty simultaneously. The Rabshakeh\'s partial truth is the paradigm for how judgment and redemption intersect at the cross.</p>',
    "11": '<p>"Then Eliakim, Shebna, and Joah said to the Rabshakeh, \'Please speak to your servants in Aramaic, for we understand it; do not speak to us in the language of Judah within the hearing of the people on the wall.\'" The officials\' request to communicate privately — to keep the threatening message from the common people — parallels the religious leaders\' fear of popular perception of Jesus: Matt 21:46, "they feared the multitudes"; Luke 20:19, "they feared the people." The desire to handle the crisis through elite negotiation rather than open communication reflects the perennial temptation of leadership to manage rather than trust.</p>',
    "12": '<p>"But the Rabshakeh said, \'Has my master sent me to speak these words to your master and to you, and not to the men who are sitting on the wall, who are doomed with you to eat their own dung and drink their own urine?\'" The deliberate public humiliation — circumventing the leadership to address the frightened populace directly — is a propaganda tactic that the passion narratives also display. The mockery of Jesus was public (Matt 27:39-44: passersby, chief priests, scribes, elders, and the two robbers all taunt Jesus on the cross), designed to undermine popular confidence that YHWH supported him. The Rabshakeh\'s brutal rhetoric and the Calvary crowd\'s mockery share the same structure: overwhelming public display of the enemy\'s contempt for faith.</p>',
    "13": '<p>"Then the Rabshakeh stood and called out in a loud voice in the language of Judah: \'Hear the words of the great king, the king of Assyria!\'" The authoritative proclamation in the people\'s own language is the parody of prophetic speech. The Rabshakeh makes himself the mouth of the "great king" — the exact form that the prophets use: "Thus says YHWH." Christ proclaims with his own authority ("you have heard it said... but I say to you," Matt 5:21-48), not as the mouth of another but as the one whose word is the divine word. The parody of prophetic authority here anticipates the false prophet of Rev 13:11-14 who "speaks like a dragon."</p>',
    "14": '<p>"Thus says the king: \'Do not let Hezekiah deceive you, for he will not be able to deliver you.\'" The charge of deception against the one who trusts in YHWH — "he will not be able to deliver you" — is the passion-week charge. Matt 27:63: "Sir, we remember how that impostor said, while he was still alive, \'After three days I will rise.\'" The "deceiver" charge against Jesus by the chief priests mirrors the Rabshakeh\'s charge against Hezekiah: both accusations are designed to break the people\'s trust before the divine act of deliverance that proves the charge false. The resurrection refutes both the Rabshakeh and the chief priests.</p>',
    "15": '<p>"Do not let Hezekiah make you trust in YHWH, saying, \'YHWH will surely deliver us. This city will not be given into the hand of the king of Assyria.\'" This verse is the direct source of the Calvary mockery. Matt 27:43: "He trusts in God; let God deliver him now, if he desires him. For he said, \'I am the Son of God.\'" The logic is identical: if YHWH really supports this person/city, deliverance would already have come — the absence of immediate rescue proves the trust is misplaced. Both arguments are proved wrong: the angel strikes the Assyrian camp (37:36); the Father raises the Son from the dead (Acts 2:24). Trust in YHWH in the face of the Rabshakeh\'s argument is the posture of faith that the passion narrative demands.</p>',
    "16": '<p>"Do not listen to Hezekiah. For thus says the king of Assyria: \'Make your peace with me and come out to me. Then each one of you will eat of his own vine, and each one of his own fig tree, and each one of you will drink the water of his own cistern.\'" The false peace offer — submission to the conqueror in exchange for security and provision. Matt 4:8-9: "all these I will give you, if you will fall down and worship me." Rev 6:2: the first horseman "came out conquering, and to conquer" — the offer of peace through submission to earthly power. John 14:27: "Peace I leave with you; my peace I give to you. Not as the world gives do I give to you." The true peace that Christ gives is the opposite of the Rabshakeh\'s peace-through-surrender.</p>',
    "17": '<p>"Until I come and take you away to a land like your own land, a land of grain and wine, a land of bread and vineyards." The propaganda about a comfortable exile — a land "like your own land" as a substitute for the promised land. Rev 21:2: "I saw the holy city, new Jerusalem, coming down out of heaven from God." The true land promised to God\'s people is not a copy but the new creation itself. The Rabshakeh\'s substitute land is a counterfeit of the land-promise; Christ fulfills the land-promise by bringing his people into the presence of God himself, not a geographical replica. "In my Father\'s house are many rooms... I go to prepare a place for you" (John 14:2).</p>',
    "18": '<p>"Beware lest Hezekiah mislead you by saying, \'YHWH will deliver us.\' Has any of the gods of the nations delivered his land out of the hand of the king of Assyria?" The idol-polemic challenge: the cumulative failure of national gods to deliver constitutes evidence that YHWH will also fail. Acts 4:12 is the NT\'s direct answer: "there is salvation in no one else, for there is no other name under heaven given among men by which we must be saved." Christ is the one who delivers where all others — whether human power or idol-gods — fail. The Rabshakeh\'s argument from the gods\' failure inadvertently sets up the uniqueness that YHWH\'s deliverance will demonstrate.</p>',
    "19": '<p>"Where are the gods of Hamath and Arpad? Where are the gods of Sepharvaim? Have they delivered Samaria out of my hand?" The rhetorical survey of defeated divine powers — each failed deity a step in the argument that YHWH is next. 1 Cor 8:4-6: "we know that \'an idol has no real existence\' and that \'there is no God but one\'... yet for us there is one God, the Father, from whom are all things... and one Lord, Jesus Christ." The Rabshakeh\'s argument establishes the field of comparison in which Christ\'s resurrection stands alone: he asked "where are the gods?" — the answer is, they fell; Christ alone rose. Acts 17:29-31: "the times of ignorance God overlooked, but now he commands all people everywhere to repent, because he has fixed a day on which he will judge the world... by a man whom he has appointed; and of this he has given assurance to all by raising him from the dead."</p>',
    "20": '<p>"Who among all the gods of these countries have delivered their countries out of my hand, that YHWH should deliver Jerusalem out of my hand?" The Rabshakeh\'s culminating challenge: YHWH is just another failed deity. Isa 37:20: Hezekiah\'s prayer answers directly — "so that all the kingdoms of the earth may know that you alone are YHWH." The resurrection is God\'s ultimate answer to the Rabshakeh\'s challenge: Rom 1:4, Christ "was declared to be the Son of God in power according to the Spirit of holiness by his resurrection from the dead." The resurrection answers the challenge to divine uniqueness with a display of power over the ultimate enemy — death itself — that no national deity ever faced or overcame.</p>',
    "21": '<p>"But they were silent and answered him not a word, for the king\'s command was, \'Do not answer him.\'" The commanded silence of the people before the Rabshakeh\'s taunts. Matt 26:63: Jesus "remained silent" (esiōpa) when Caiaphas adjured him; Matt 27:14: "he gave him no answer, not even to a single charge, so that the governor was greatly amazed." Isa 53:7: "he was oppressed, and he was afflicted, yet he opened not his mouth; like a lamb that is led to the slaughter... so he opened not his mouth." The silence is not defeat but restraint — the refusal to defend oneself before the taunt, trusting YHWH to act. 1 Pet 2:23: "When he was reviled, he did not revile in return; when he suffered, he did not threaten, but continued entrusting himself to him who judges justly."</p>',
    "22": '<p>"Then Eliakim the son of Hilkiah, who was over the household, and Shebna the secretary, and Joah the son of Asaph, the recorder, came to Hezekiah with their clothes torn and told him the words of the Rabshakeh." The torn garments of grief at the blasphemous taunt and the report to the king. Matt 26:65: the high priest "tore his robes" at Jesus\'s trial, declaring blasphemy. The inversion is complete: at the Sennacherib crisis, the faithful tear their garments in anguish at blasphemy against YHWH; at the passion trial, the blasphemer tears his garments to condemn the innocent. Hezekiah\'s response (ch. 37: going to the temple, spreading the letter before YHWH, and praying) is the model that Gethsemane fulfills — the king\'s prayer in the hour of supreme threat answered by divine deliverance.</p>',
  },
}

def main():
    existing = load_comm('mkt-christ', 'isaiah')
    merge_comm(existing, ISAIAH)
    save_comm('mkt-christ', 'isaiah', existing)
    # INTENT: Verify all 22 Isaiah 36 mkt-christ verses present against interlinear
    # CHANGE? If interlinear/isaiah.json ch 36 verse count changes, update expected total
    # VERIFY: Console shows OK with 22 verses; no MISSING output
    il = json.loads((ROOT / 'data' / 'interlinear' / 'isaiah.json').read_text())
    out = json.loads((ROOT / 'data' / 'commentary' / 'mkt-christ' / 'isaiah.json').read_text())
    missing = [v for v in il.get('36', {}) if v not in out.get('36', {})]
    if missing:
        print(f'  MISSING: {missing}')
    else:
        print(f'  OK: all Isaiah 36 mkt-christ verses present ({len(il.get("36", {}))} verses)')

if __name__ == '__main__':
    main()
